11	    }
12	
13	    private let auth: CodexAuthProviding
14	    private let logger: FileLogger
15	    private let session: URLSession
16	
17	    // Thread-safe email cache readable from nonisolated resolveActiveAccount()
18	    // without blocking the cooperative thread pool.
19	    private let _cachedEmail = OSAllocatedUnfairLock<AccountEmail?>(initialState: nil)
20	    private var lastKnownMetrics: [UsageMetric] = []
21	
22	    // Fixed window durations (Codex policy mirrors Claude's windows)
23	    private static let sessionWindowMinutes = DurationMinutes(rawValue: 300)
24	    private static let weeklyWindowMinutes = DurationMinutes(rawValue: 10080)
25	    // Codex credit pool size per the current plan definition
26	    private static let creditPoolTotal: Double = 1000
27	
28	    // Known-valid literal — force-unwrap is safe here
29	    private static let apiURL = URL(string: "https://chatgpt.com/backend-api/wham/usage")! // known-valid literal
