334	            let nextIndex = body.index(index, offsetBy: 2)
335	            guard let byte = UInt8(body[index..<nextIndex], radix: 16) else { return nil }
336	            bytes.append(byte)
337	            index = nextIndex
338	        }
339	        return String(bytes: bytes, encoding: .utf8)
340	    }
