53	/// An ISO 8601 datetime string without sub-second precision.
54	/// Stores the raw string and lazily parses it when `.date` is accessed.
55	public struct ISODate: RawRepresentable, Codable, Equatable, Hashable, Sendable {
56	    public let rawValue: String
57	    public init(rawValue: String) { self.rawValue = rawValue }
58	
59	    /// Creates an ISODate by formatting a Date with the standard ISO 8601 format (no fractional seconds).
60	    public init(date: Date) {
61	        // New formatter per call — ISO8601DateFormatter is not thread-safe; acceptable for this cold path
62	        rawValue = ISO8601DateFormatter().string(from: date)
63	    }
64	
65	    /// Parses the stored string and returns the corresponding Date, or nil if parsing fails.
66	    public var date: Date? {
67	        // New formatter per call — ISO8601DateFormatter is not thread-safe; acceptable for this cold path
68	        ISO8601DateFormatter().date(from: rawValue)
69	    }
70	
71	    /// Whether `rawValue` parses as a valid ISO 8601 datetime. Connectors must
72	    /// produce values for which this is `true` — see `parsing(_:)` for the
73	    /// validating factory enforced by `UsageMetric`'s encoder in DEBUG builds.
74	    public var isStrictlyValid: Bool { date != nil }
75	
76	    /// Strict factory: returns nil unless `raw` parses as a valid ISO 8601
77	    /// datetime. Use this at every connector boundary that consumes a string
78	    /// from an external API — `init(rawValue:)` stays lenient for Codable
79	    /// round-trips of pre-existing data.
80	    public static func parsing(_ raw: String) -> ISODate? {
81	        // New formatter per call — ISO8601DateFormatter is not thread-safe; acceptable for this cold path
82	        guard ISO8601DateFormatter().date(from: raw) != nil else { return nil }
83	        return ISODate(rawValue: raw)
84	    }
85	
86	    /// Flexible factory: accepts strict ISO 8601 datetime, or a calendar date
87	    /// `yyyy-MM-dd` which is promoted to UTC midnight (`T00:00:00Z`). Some
88	    /// vendor APIs (notably GitHub Copilot's `quota_reset_date`) hand back
89	    /// date-only values; without normalization the rest of the app — which
90	    /// expects a parseable datetime — would silently treat them as missing.
91	    public static func parsingFlexibleDate(_ raw: String) -> ISODate? {
92	        if let strict = parsing(raw) { return strict }
93	
94	        // Regex shape-check before DateFormatter: `isLenient = false` is not
95	        // enough — DateFormatter still accepts variant separators like
96	        // `2026/06/06` against a `yyyy-MM-dd` pattern. We want to reject
97	        // anything that isn't exactly the documented upstream shape.
98	        let pattern = #/^\d{4}-\d{2}-\d{2}$/#
99	        guard (try? pattern.wholeMatch(in: raw)) != nil else { return nil }
100	
101	        let dateOnly = DateFormatter()
102	        dateOnly.dateFormat = "yyyy-MM-dd"
103	        dateOnly.timeZone = TimeZone(identifier: "UTC")
104	        dateOnly.locale = Locale(identifier: "en_US_POSIX")
105	        guard let date = dateOnly.date(from: raw) else { return nil }
106	        return ISODate(date: date)
107	    }
