109	    public init(from decoder: Decoder) throws {
110	        rawValue = try decoder.singleValueContainer().decode(String.self)
111	    }
112	
113	    public func encode(to encoder: Encoder) throws {
114	        var container = encoder.singleValueContainer()
115	        try container.encode(rawValue)
116	    }
117	}
