3	public actor CopilotActiveAccountMonitor {
4	    // 15 s mirrors the Codex/Claude monitors — short enough to react to
5	    // `gh auth switch` without hammering the disk.
6	    public static let defaultInterval: Duration = .seconds(15)
7	
8	    private let environment: [String: String]
9	    private let hostsFilePathOverride: String?
10	    private let fileManager: FileManager
11	    private let logger: FileLogger
12	    private let interval: Duration
13	    /// Emits the new active GitHub login so callers can invalidate any cached
14	    /// identity and force a fresh fetch.
15	    private let onActiveAccountChanged: (@Sendable (AccountEmail) async -> Void)?
16	
17	    private var monitorTask: Task<Void, Never>?
18	    private var lastObservedLogin: AccountEmail?
19	
20	    public init(
21	        environment: [String: String] = ProcessInfo.processInfo.environment,
22	        hostsFilePathOverride: String? = nil,
23	        fileManager: FileManager = .default,
24	        logger: FileLogger = Loggers.copilot,
25	        interval: Duration = CopilotActiveAccountMonitor.defaultInterval,
26	        onActiveAccountChanged: (@Sendable (AccountEmail) async -> Void)? = nil
27	    ) {
28	        self.environment = environment
29	        self.hostsFilePathOverride = hostsFilePathOverride
30	        self.fileManager = fileManager
31	        self.logger = logger
32	        self.interval = interval
33	        self.onActiveAccountChanged = onActiveAccountChanged
34	    }
35	
36	    public func start() {
37	        guard monitorTask == nil else {
38	            logger.log(.warning, "Copilot active-account monitor already running")
39	            return
40	        }
41	        logger.log(.info, "Starting Copilot active-account monitor with interval \(interval)")
42	        monitorTask = Task {
43	            while !Task.isCancelled {
44	                await self.checkOnce()
45	                try? await Task.sleep(for: self.interval)
46	                guard !Task.isCancelled else { break }
47	            }
48	        }
49	    }
50	
51	    public func stop() {
52	        monitorTask?.cancel()
53	        monitorTask = nil
54	        logger.log(.info, "Copilot active-account monitor stopped")
55	    }
56	
57	    public func checkOnce() async {
58	        guard let login = readActiveLogin() else {
59	            // `gh auth switch` rewrites hosts.yml; during the brief window between
60	            // unlink and relink we may see no `user:` line. Trust positive signals
61	            // only — preserve the previous observed state otherwise.
62	            logger.log(.debug, "Copilot active login unresolved — keeping previous state")
63	            return
64	        }
65	
66	        let previous = lastObservedLogin
67	        lastObservedLogin = login
68	        // Skip the first resolution (startup) to avoid a redundant forced poll
69	        // — only fire on genuine switches.
70	        if let previous, previous != login {
71	            logger.log(.info, "Copilot active login switched: \(login)")
72	            await onActiveAccountChanged?(login)
73	        }
74	    }
75	
76	    private func readActiveLogin() -> AccountEmail? {
77	        for path in hostsFileCandidatePaths() where fileManager.fileExists(atPath: path) {
78	            guard let data = fileManager.contents(atPath: path),
79	                  let text = String(data: data, encoding: .utf8) else {
80	                logger.log(.debug, "Failed to read gh hosts.yml at \(path)")
81	                continue
82	            }
83	            let config = CopilotAuth.parseHostsYAML(text)
84	            if let login = config.activeLogin, !login.isEmpty {
85	                return AccountEmail(rawValue: login)
86	            }
87	        }
88	        return nil
89	    }
90	
91	    private func hostsFileCandidatePaths() -> [String] {
92	        if let override = hostsFilePathOverride {
93	            return [override]
94	        }
95	        let home = fileManager.homeDirectoryForCurrentUser.path
96	        var paths: [String] = []
97	        if let ghConfigDir = environment["GH_CONFIG_DIR"], !ghConfigDir.isEmpty {
98	            paths.append("\(ghConfigDir)/hosts.yml")
99	        }
100	        if let xdg = environment["XDG_CONFIG_HOME"], !xdg.isEmpty {
101	            paths.append("\(xdg)/gh/hosts.yml")
