import Foundation

public actor CopilotActiveAccountMonitor {
    // 15 s mirrors the Codex/Claude monitors — short enough to react to
    // `gh auth switch` without hammering the disk.
    public static let defaultInterval: Duration = .seconds(15)

    private let environment: [String: String]
    private let hostsFilePathOverride: String?
    private let fileManager: FileManager
    private let logger: FileLogger
    private let interval: Duration
    /// Emits the new active GitHub login so callers can invalidate any cached
    /// identity and force a fresh fetch.
    private let onActiveAccountChanged: (@Sendable (AccountEmail) async -> Void)?

    private var monitorTask: Task<Void, Never>?
    private var lastObservedLogin: AccountEmail?

    public init(
        environment: [String: String] = ProcessInfo.processInfo.environment,
        hostsFilePathOverride: String? = nil,
        fileManager: FileManager = .default,
        logger: FileLogger = Loggers.copilot,
        interval: Duration = CopilotActiveAccountMonitor.defaultInterval,
        onActiveAccountChanged: (@Sendable (AccountEmail) async -> Void)? = nil
    ) {
        self.environment = environment
        self.hostsFilePathOverride = hostsFilePathOverride
        self.fileManager = fileManager
        self.logger = logger
        self.interval = interval
        self.onActiveAccountChanged = onActiveAccountChanged
    }

    public func start() {
        guard monitorTask == nil else {
            logger.log(.warning, "Copilot active-account monitor already running")
            return
        }
        logger.log(.info, "Starting Copilot active-account monitor with interval \(interval)")
        monitorTask = Task {
            while !Task.isCancelled {
                await self.checkOnce()
                try? await Task.sleep(for: self.interval)
                guard !Task.isCancelled else { break }
            }
        }
    }

    public func stop() {
        monitorTask?.cancel()
        monitorTask = nil
        logger.log(.info, "Copilot active-account monitor stopped")
    }

    public func checkOnce() async {
        guard let login = readActiveLogin() else {
            // `gh auth switch` rewrites hosts.yml; during the brief window between
            // unlink and relink we may see no `user:` line. Trust positive signals
            // only — preserve the previous observed state otherwise.
            logger.log(.debug, "Copilot active login unresolved — keeping previous state")
            return
        }

        let previous = lastObservedLogin
        lastObservedLogin = login
        // Skip the first resolution (startup) to avoid a redundant forced poll
        // — only fire on genuine switches.
        if let previous, previous != login {
            logger.log(.info, "Copilot active login switched: \(login)")
            await onActiveAccountChanged?(login)
        }
    }

    private func readActiveLogin() -> AccountEmail? {
        for path in hostsFileCandidatePaths() where fileManager.fileExists(atPath: path) {
            guard let data = fileManager.contents(atPath: path),
                  let text = String(data: data, encoding: .utf8) else {
                logger.log(.debug, "Failed to read gh hosts.yml at \(path)")
                continue
            }
            let config = CopilotAuth.parseHostsYAML(text)
            if let login = config.activeLogin, !login.isEmpty {
                return AccountEmail(rawValue: login)
            }
        }
        return nil
    }

    private func hostsFileCandidatePaths() -> [String] {
        if let override = hostsFilePathOverride {
            return [override]
        }
        let home = fileManager.homeDirectoryForCurrentUser.path
        var paths: [String] = []
        if let ghConfigDir = environment["GH_CONFIG_DIR"], !ghConfigDir.isEmpty {
            paths.append("\(ghConfigDir)/hosts.yml")
        }
        if let xdg = environment["XDG_CONFIG_HOME"], !xdg.isEmpty {
            paths.append("\(xdg)/gh/hosts.yml")
        }
        paths.append("\(home)/.config/gh/hosts.yml")
        return paths
    }
}

import Foundation

public actor CodexStatusConnector: StatusConnector {
    nonisolated public let vendor: Vendor = .codex

    private let logger: FileLogger
    private let session: URLSession
    private let endpointURLString: String

    public static let defaultEndpoint = "https://status.openai.com/api/v2/incidents/unresolved.json"

    public init(
        logger: FileLogger = Loggers.codex,
        session: URLSession = .shared,
        endpointURLString: String = CodexStatusConnector.defaultEndpoint
    ) {
        self.logger = logger
        self.session = session
        self.endpointURLString = endpointURLString
    }

    public func fetchOutages() async throws -> [Outage] {
        guard let url = URL(string: endpointURLString) else {
            throw StatusConnectorError.invalidURL(rawValue: endpointURLString)
        }
        var request = URLRequest(url: url)
        request.timeoutInterval = CodexConstants.requestTimeoutSeconds
        request.setValue("application/json", forHTTPHeaderField: "Accept")

        logger.log(.debug, "Fetching Codex status from \(endpointURLString)")

        let data: Data
        let response: URLResponse
        do {
            (data, response) = try await session.data(for: request)
        } catch {
            logger.log(.warning, "Codex status endpoint network error: \(error)")
            throw StatusConnectorError.networkError(underlying: error, url: endpointURLString)
        }

        let httpCode = (response as? HTTPURLResponse)?.statusCode ?? -1
        guard httpCode == 200 else {
            logger.log(.warning, "Codex status endpoint returned HTTP \(httpCode)")
            throw StatusConnectorError.unexpectedResponse(statusCode: httpCode, url: endpointURLString)
        }

        let decoded: StatuspageIncidentsResponse
        do {
            decoded = try JSONDecoder().decode(StatuspageIncidentsResponse.self, from: data)
        } catch {
            logger.log(.error, "Codex status endpoint parse error: \(error)")
            throw StatusConnectorError.parseError(underlying: error, url: endpointURLString)
        }

        let outages: [Outage] = decoded.incidents.compactMap { incident in
            // "none" impact means the incident is informational with no user-facing effect
            guard incident.impact != "none" else { return nil }
            let severity = OutageSeverity(rawValue: incident.impact)
            let href: URL?
            if let raw = incident.shortlink {
                href = URL(string: raw)
            } else {
                href = nil
            }
            return Outage(
                vendor: vendor,
                errorMessage: incident.name,
                severity: severity,
                since: incident.createdAt,
                href: href
            )
        }
        logger.log(.info, "Codex status: \(outages.count) active outage(s)")
        return outages
    }

    // MARK: - DTOs

    private struct StatuspageIncidentsResponse: Decodable {
        let incidents: [StatuspageIncident]
    }

    private struct StatuspageIncident: Decodable {
        let name: String
        let impact: String
        let createdAt: ISODate
        let shortlink: String?

        private enum CodingKeys: String, CodingKey {
            case name
            case impact
            case createdAt = "created_at"
            case shortlink
        }
    }
}

