    /// MUST NOT call `SecItemAdd` / `SecItemUpdate` / `SecItemDelete`,
    /// MUST NOT write to vendor config files,
    /// MUST NOT shell out to `<vendor> auth login`.
    func locate() async throws -> Credentials
}

