import Foundation

/// Compile-time list of every assistant the application knows how to
/// poll. Adding a vendor is exactly: implement the contract under the
/// vendor's own `*Plugin` namespace, then prepend its bundle below. No
/// edits to `AppDelegate`, `Loggers`, or any cross-cutting subsystem are
/// required beyond their declared plugin points.
///
/// The list intentionally stays empty until each vendor's plugin module
/// is migrated onto the contract — the registry compiles regardless of
/// how many vendors have landed, so the framework can be introduced
/// before any connector is rewritten.
public enum VendorRegistry {
    public static var bundles: [VendorBundle] {
        registeredBundles
    }

    /// Mutable internal storage so the registry is populated in one place
    /// — bundles append themselves at module-load time via the per-vendor
    /// `*Plugin.register()` static call (see migration plan §3).
    nonisolated(unsafe) private static var registeredBundles: [VendorBundle] = []

    /// Registers a bundle. Idempotent on the `vendor` key — calling twice
    /// with the same vendor replaces the previously registered bundle so
    /// tests can inject mocks without leaking across runs.
    public static func register(_ bundle: VendorBundle) {
        registeredBundles.removeAll { $0.vendor == bundle.vendor }
        registeredBundles.append(bundle)
    }

    /// Test hook — clears the registry so a `setUp()` can prime it from
    /// scratch. Production code never calls this.
    public static func resetForTesting() {
        registeredBundles.removeAll()
    }

    public static func bundle(for vendor: Vendor) -> VendorBundle? {
        registeredBundles.first { $0.vendor == vendor }
    }
}

