/// Replaces email-looking substrings with the literal `<email>`. Composed
/// by per-vendor sanitizers in their `sanitize(_ message:)` and (after
/// JSON masking) `sanitize(_ payload:)` paths so log lines that splice
/// payload fragments into prose still get scrubbed.
public struct EmailPatternSanitizer: Sendable {
    public static let placeholder = "<email>"

    /// Conservative shape — `RFC 5322` is intractable with a regex; the
    /// goal here is to catch every realistic vendor-emitted email with no
    /// false negatives, accepting some false positives (e.g. version
    /// strings with `@`) which only affect log readability.
    private static let pattern: Regex<Substring> = {
        // swiftlint:disable:next force_try
        try! Regex(#"[A-Za-z0-9._+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}"#)
    }()

    public init() {}

    public func sanitize(_ message: String) -> String {
        message.replacing(Self.pattern, with: Self.placeholder)
    }
}

